head.script:
//
    (function () {
      try {
        var theme = window.localStorage && window.localStorage.getItem('gg:theme');
        if (theme !== 'dark') {
          theme = 'light';
          if (window.localStorage) window.localStorage.setItem('gg:theme', theme);
        }
        document.documentElement.setAttribute('data-gg-theme', theme);
      } catch (error) {}
    }());
    //

head.b:skin:
:root {
  color-scheme: light;
  --gg-handler:10px;
  --gg-hit-min: 44px;
  --gg-surface-page: #f3efe4;
  --gg-surface-article: rgba(255,255,255,.16);
  --gg-surface-panel: #f6f1e6;
  --gg-surface-interactive: rgba(255,255,255,.48);
  --gg-surface-interactive-strong: rgba(255,255,255,.66);
  --gg-divider: rgba(32,26,28,.12);
  --gg-divider-strong: rgba(32,26,28,.18);
  --gg-border-interactive: rgba(32,26,28,.18);
  --gg-ink: #171512;
  --gg-ink-soft: #5c564b;
  --gg-accent: #171512;
  --gg-accent-soft: #6d6457;
  --gg-accent-contrast: #fff;
  --gg-focus-ring: 2px solid var(--gg-accent);
  --gg-shadow-soft: 0 8px 24px rgba(32,26,28,.028);
  --gg-font-sans: ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
  --gg-dock-offset-bottom: max(10px, env(safe-area-inset-bottom));
  --gg-toolbar-item-min-height: 50px;
  --gg-toolbar-pad: 6px;
  --gg-toolbar-surface: var(--gg-surface-interactive-strong);
  --gg-dock-track-height: calc(var(--gg-toolbar-item-min-height) + (var(--gg-toolbar-pad) * 2));
  --gg-dock-clearance: calc(var(--gg-dock-track-height) + var(--gg-dock-offset-bottom));
  --gg-shell-bottom-clearance: calc(var(--gg-dock-clearance) + 20px);
  --gg-entry-row-pad-y: 2px;
  --gg-entry-row-pad-x: 2px;
  --gg-entry-row-gap: 2px;
  --gg-entry-row-divider-size: 1px;
  --gg-entry-row-divider: rgba(32,26,28,.14);
  --gg-entry-row-action-hover-bg: rgba(255,255,255,.36);
  --gg-entry-row-title-size: 18px;
  --gg-entry-row-title-line: 1.28;
  --gg-entry-row-title-weight: 600;
  --gg-article-border: rgba(32,26,28,.1);
  --gg-article-pad-y: 16px;
  --gg-article-pad-x: 0px;
  --gg-detail-bottom-clearance: 44px;
  --gg-ease: 180ms ease;
}
html[data-gg-theme='dark'] {
  color-scheme: dark;
  --gg-surface-page: #050505;
  --gg-surface-article:rgba(0,0,0,0);
  --gg-surface-panel: #0d0d0b;
  --gg-surface-interactive:rgba(255,255,255,.1);
  --gg-surface-interactive-strong:rgba(255,255,255,.14);
  --gg-divider:rgba(255,255,255,.14);
  --gg-divider-strong:rgba(255,255,255,.22);
  --gg-border-interactive:rgba(255,255,255,.18);
  --gg-ink: #eee8db;
  --gg-ink-soft: #c7bda9;
  --gg-accent: #f4eddf;
  --gg-accent-soft: #d2c6b0;
  --gg-entry-row-divider:rgba(255,255,255,.14);
  --gg-article-border:rgba(255,255,255,.1);
}
*{box-sizing:border-box}
html{scroll-behavior:smooth}
html,body{min-height:100%}
body{margin:0;background:var(--gg-surface-page);color:var(--gg-ink);font:15px/1.58 var(--gg-font-sans);text-rendering:optimizeLegibility;-webkit-font-smoothing:antialiased}
body[data-gg-scroll-lock='true']{overflow:hidden}
a{color:inherit;text-decoration:none}a:hover{color:var(--gg-accent)}
a:focus-visible,button:focus-visible,input:focus-visible,textarea:focus-visible,select:focus-visible{outline:var(--gg-focus-ring);outline-offset:2px}
img{max-width:100%;height:auto;display:block}
.skip-navigation{position:absolute;top:0;left:12px;z-index:120;padding:10px 14px;border-radius:12px;background:var(--gg-surface-interactive);box-shadow:var(--gg-shadow-soft);color:var(--gg-ink);transform:translateY(calc(-100% - 8px));transition:transform var(--gg-ease),color var(--gg-ease)}
.skip-navigation:focus,.skip-navigation:focus-visible{transform:translateY(12px)}
.gg-visually-hidden{position:absolute!important;width:1px;height:1px;padding:0;margin:-1px;overflow:hidden;clip:rect(0 0 0 0);white-space:nowrap;border:0}
.gg-shell{min-height:100vh;padding:12px 12px var(--gg-shell-bottom-clearance)}
.gg-main{width:min(100%,600px);margin:0 auto}.gg-site-head{display:grid;gap:0;position:fixed;top:var(--gg-dock-offset-bottom);max-width: none;width: var(--gg-dock-width);}.gg-site-head__eyebrow{margin:0 0 6px;color:var(--gg-accent-soft);font:600 11px/1.2 -apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;letter-spacing:.16em;text-transform:uppercase}.gg-site-head__title{margin:0;font-size:clamp(18px,7vw,19px);line-height:1.08;letter-spacing:-.03em}.gg-site-head__summary{margin:8px 0 0;max-width:62ch;color:var(--gg-ink-soft)}
.gg-listing-toolbar{position:sticky;top:max(8px,env(safe-area-inset-top));z-index:18;display:grid;grid-template-columns:minmax(0,1fr) auto;align-items:center;gap:12px;min-height:68px;padding:8px 10px;border:var(--gg-entry-row-divider-size) solid var(--gg-entry-row-divider);border-bottom:0;border-radius:14px 14px 0 0;background:var(--gg-toolbar-surface);box-shadow:var(--gg-shadow-soft);-webkit-backdrop-filter:blur(16px) saturate(145%);backdrop-filter:blur(16px) saturate(145%)}.gg-root-profile__card{display:grid;grid-template-columns:44px minmax(0,1fr);align-items:center;gap:10px;min-width:0}.gg-root-profile__avatar{display:grid;width:44px;height:44px;overflow:hidden;border-radius:999px;background:var(--gg-surface-interactive);place-items:center}.gg-root-profile__image{width:100%;height:100%;object-fit:cover}.gg-root-profile__copy{display:grid;min-width:0;gap:2px}.gg-root-profile__name{overflow:hidden;color:var(--gg-ink);font:650 17px/1.15 var(--gg-font-sans);text-overflow:ellipsis;white-space:nowrap}.gg-root-profile__meta{overflow:hidden;color:var(--gg-accent-soft);font:500 12px/1.25 var(--gg-font-sans);text-overflow:ellipsis;white-space:nowrap}.gg-listing-filter{position:relative;justify-self:end}.gg-listing-toolbar__filter{display:inline-flex;align-items:center;justify-content:center;gap:6px;min-height:38px;max-width:42vw;padding:0 12px;border:0;border-radius:999px;background:#fbfaf4;color:var(--gg-ink);font:650 13px/1.2 var(--gg-font-sans);letter-spacing:0;cursor:pointer}.gg-listing-toolbar__filter-label{min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.gg-listing-filter__menu{position:absolute;top:calc(100% + 6px);right:0;z-index:20;display:grid;gap:2px;width:max-content;min-width:180px;max-width:min(78vw,260px);padding:6px;border:1px solid var(--gg-divider);border-radius:12px;background:#fbfaf4;box-shadow:var(--gg-shadow-soft);opacity:0;visibility:hidden;pointer-events:none;transform:translateY(-4px);transition:opacity var(--gg-ease),transform var(--gg-ease),visibility var(--gg-ease)}.gg-listing-filter:hover .gg-listing-filter__menu,.gg-listing-filter:focus-within .gg-listing-filter__menu,.gg-listing-toolbar[data-gg-filter-open='true'] .gg-listing-filter__menu{opacity:1;visibility:visible;pointer-events:auto;transform:translateY(0)}.gg-listing-filter__item{display:flex;align-items:center;min-height:40px;padding:0 12px;border-radius:8px;color:var(--gg-ink);font:600 13px/1.25 var(--gg-font-sans)}.gg-listing-filter__item:hover,.gg-listing-filter__item:focus-visible{background:#f4f3ed}.gg-entry-list{display:grid;gap:0;border-radius:0 0 14px 14px;background:transparent;overflow:clip}.gg-entry-row{display:grid;grid-template-columns:minmax(0,1fr) auto;align-items:center;gap:var(--gg-entry-row-gap);padding:var(--gg-entry-row-pad-y) var(--gg-entry-row-pad-x);border-bottom:var(--gg-entry-row-divider-size) solid var(--gg-entry-row-divider);background:transparent}.gg-entry-row:last-child{border-bottom:0}.gg-entry-row__title{min-width:0;margin:0;color:var(--gg-ink);font:var(--gg-entry-row-title-weight) var(--gg-entry-row-title-size)/var(--gg-entry-row-title-line) var(--gg-font-sans)}.gg-entry-row__title-trigger{display:block;width:100%;padding:0;border:0;background:transparent;color:inherit;font:inherit;text-align:left;cursor:pointer;overflow-wrap:anywhere}.gg-entry-row__action{display:inline-flex;align-items:center;justify-content:flex-end;min-height:44px;padding:0 6px;border:0;border-radius:12px;background:transparent;color:var(--gg-accent-soft);font:600 12px/1.2 var(--gg-font-sans);white-space:nowrap;cursor:pointer}.gg-detail-outline[data-gg-outline-mode='pagination']{z-index:16;}.gg-detail-outline[data-gg-outline-mode='pagination'] .gg-detail-outline__peek{display:grid;grid-template-columns:minmax(0,1fr) auto;align-items:center;gap:10px;width:100%;min-height:44px;padding:10px 12px;border:0;background:transparent;color:var(--gg-ink);text-align:left;cursor:default}.gg-listing-pagination__pages{display:inline-flex;align-items:center;justify-content:flex-end;gap:4px;min-width:0}.gg-listing-pagination__link,.gg-listing-pagination__page,.gg-listing-pagination__ellipsis{display:inline-flex;align-items:center;justify-content:center;min-width:36px;min-height:36px;padding:0 10px;border-radius:999px;color:var(--gg-ink);font:650 12px/1 var(--gg-font-sans);white-space:nowrap}.gg-listing-pagination__page{background:var(--gg-accent);color:var(--gg-accent-contrast)}.gg-listing-pagination__ellipsis{min-width:20px;padding:0 4px;color:var(--gg-accent-soft)}.gg-listing-pagination__link{background:var(--gg-surface-interactive)}.gg-listing-pagination__link.is-disabled{color:var(--gg-accent-soft);opacity:.56}
.gg-article{display:grid;gap:0;width:100%;max-width:62ch;justify-self:center;padding:var(--gg-article-pad-y) var(--gg-article-pad-x) calc(28px + var(--gg-detail-bottom-clearance));border-top:1px solid var(--gg-article-border);border-bottom:1px solid var(--gg-article-border);background:var(--gg-surface-article)}.gg-article__title{margin:0 0 10px;font-size:clamp(24px,8vw,42px);line-height:1.1}.gg-post-body{max-width:none;color:var(--gg-ink);font-size:16px}.gg-post-body p,.gg-post-body ul,.gg-post-body ol,.gg-post-body blockquote{margin:0 0 1em}.gg-post-body img{margin:1.5em auto;border-radius:18px}.gg-breadcrumbs{margin:0 0 10px;color:var(--gg-accent-soft);font:500 12px/1.5 var(--gg-font-sans)}
.gg-dock{position:fixed;left:50%;bottom:var(--gg-dock-offset-bottom);z-index:40;transform:translateX(-50%);max-width:calc(100% - 24px)}.gg-sheet[hidden],.gg-detail-outline[hidden],.gg-search-empty[hidden],.gg-error404[hidden]{display:none!important}
@media (min-width:769px){:root{--gg-entry-row-pad-y:2px;--gg-entry-row-title-size:18px;--gg-article-pad-y:22px}.gg-shell{padding-left:16px;padding-right:16px}}
@media (prefers-reduced-motion: reduce){*,*::before,*::after{scroll-behavior:auto!important;animation-duration:.01ms!important;animation-iteration-count:1!important;transition-duration:.01ms!important}}

body.script:
//
(function () {
  var GG = window.GG = window.GG || {};
  var startup = GG.__startup = GG.__startup || {};
  var body = document.body;
  var standalone = false;

  try { performance.mark('gg:boot:start'); } catch (error) {}

  startup.startedAt = window.performance && typeof window.performance.now === 'function'
    ? window.performance.now()
    : 0;
  startup.launchPath = window.location.pathname || '/';

  try {
    standalone = !!(window.matchMedia && window.matchMedia('(display-mode: standalone)').matches);
  } catch (error) {
    standalone = false;
  }

  if (!standalone && window.navigator && window.navigator.standalone === true) {
    standalone = true;
  }

  startup.displayMode = standalone ? 'standalone' : 'browser';
  startup.longTasks = Array.isArray(startup.longTasks) ? startup.longTasks : [];

  if (!body) return;

  body.setAttribute('data-gg-boot', 'starting');
  body.setAttribute('data-gg-hydration', 'critical');
  body.setAttribute('data-gg-network', window.navigator && window.navigator.onLine === false ? 'offline' : 'online');
  body.setAttribute('data-gg-display-mode', startup.displayMode);
  body.setAttribute('data-gg-launch-path', startup.launchPath);
}());
//
